import{_ as e,o as l,c as r,a3 as a}from"./chunks/framework.BTFg6ESq.js";const h=JSON.parse('{"title":"处理器详解与执行顺序","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/context-pipeline/processors.md","filePath":"user-guide/tools/llm-chat/context-pipeline/processors.md","lastUpdated":1778244893000}'),s={name:"user-guide/tools/llm-chat/context-pipeline/processors.md"};function o(n,t,d,i,g,f){return l(),r("div",null,[...t[0]||(t[0]=[a('<div><h1 id="处理器详解与执行顺序" tabindex="-1">处理器详解与执行顺序 <a class="header-anchor" href="#处理器详解与执行顺序" aria-label="Permalink to &quot;处理器详解与执行顺序&quot;">​</a></h1><p>上下文管道由一系列有序的处理器组成。了解它们的默认执行顺序有助于你更好地调试和优化 Prompt。</p><h2 id="默认处理器序列" tabindex="-1">默认处理器序列 <a class="header-anchor" href="#默认处理器序列" aria-label="Permalink to &quot;默认处理器序列&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">顺序</th><th style="text-align:left;">处理器名称</th><th style="text-align:left;">核心职责</th></tr></thead><tbody><tr><td style="text-align:left;">1</td><td style="text-align:left;"><strong>Session Loader</strong></td><td style="text-align:left;">从树状会话中提取当前活跃路径的线性消息列表。</td></tr><tr><td style="text-align:left;">2</td><td style="text-align:left;"><strong>Regex Processor</strong></td><td style="text-align:left;">执行全局、Agent 及用户层的<a href="./regex-pipeline">正则替换规则</a>。</td></tr><tr><td style="text-align:left;">3</td><td style="text-align:left;"><strong>Injection Assembler</strong></td><td style="text-align:left;">处理 Agent 预设消息的注入，包括深度注入和锚点定位。</td></tr><tr><td style="text-align:left;">4</td><td style="text-align:left;"><strong>Knowledge Processor</strong></td><td style="text-align:left;">执行 RAG 检索，将<a href="./knowledge-processor">知识库</a>条目注入上下文。</td></tr><tr><td style="text-align:left;">5</td><td style="text-align:left;"><strong>Transcription Processor</strong></td><td style="text-align:left;">处理附件的转写结果及纯文本文件的内容提取。</td></tr><tr><td style="text-align:left;">6</td><td style="text-align:left;"><strong>Worldbook Processor</strong></td><td style="text-align:left;">扫描关键词并注入关联的<a href="./../worldbook/index">世界书</a>条目。</td></tr><tr><td style="text-align:left;">7</td><td style="text-align:left;"><strong>Token Limiter</strong></td><td style="text-align:left;">核心预算管理，按优先级裁剪超长上下文。</td></tr><tr><td style="text-align:left;">8</td><td style="text-align:left;"><strong>Async Task Processor</strong></td><td style="text-align:left;">汇总并注入关联的异步任务执行状态。</td></tr><tr><td style="text-align:left;">9</td><td style="text-align:left;"><strong>Variable Processor</strong></td><td style="text-align:left;">处理<a href="./../macro-system/session-variables">会话变量</a>的动态展开与快照。</td></tr><tr><td style="text-align:left;">10</td><td style="text-align:left;"><strong>Macro Processor</strong></td><td style="text-align:left;">展开 <code>{{宏}}</code>，执行三阶段宏处理管道。</td></tr><tr><td style="text-align:left;">11</td><td style="text-align:left;"><strong>Message Formatter</strong></td><td style="text-align:left;">调整消息结构以符合 OpenAI/Claude/Gemini 等厂商的 API 要求。</td></tr><tr><td style="text-align:left;">12</td><td style="text-align:left;"><strong>Asset Resolver</strong></td><td style="text-align:left;">将资产占位符转换为最终的 Base64 或安全资源 URL。</td></tr></tbody></table><h2 id="关键处理逻辑说明" tabindex="-1">关键处理逻辑说明 <a class="header-anchor" href="#关键处理逻辑说明" aria-label="Permalink to &quot;关键处理逻辑说明&quot;">​</a></h2><h3 id="_1-注入与顺序" tabindex="-1">1. 注入与顺序 <a class="header-anchor" href="#_1-注入与顺序" aria-label="Permalink to &quot;1. 注入与顺序&quot;">​</a></h3><ul><li><strong>Session Loader</strong> 总是最先运行，因为它提供了后续处理器所需的基础消息流。</li><li><strong>Regex Processor</strong> 运行较早，确保后续处理器（如 Worldbook）扫描的是经过清洗后的文本。</li><li><strong>Macro Processor</strong> 运行较晚，因为它可能需要引用由之前处理器（如 Knowledge）注入的内容。</li></ul><h3 id="_2-异步任务注入" tabindex="-1">2. 异步任务注入 <a class="header-anchor" href="#_2-异步任务注入" aria-label="Permalink to &quot;2. 异步任务注入&quot;">​</a></h3><p><strong>Async Task Processor</strong> 会检查当前会话关联的后台任务（如文件下载、FFmpeg 处理）。如果任务正在运行或已完成，它会将任务状态注入上下文，使 LLM 能够感知任务进度。</p><h3 id="_3-厂商适配-formatter" tabindex="-1">3. 厂商适配 (Formatter) <a class="header-anchor" href="#_3-厂商适配-formatter" aria-label="Permalink to &quot;3. 厂商适配 (Formatter)&quot;">​</a></h3><p>不同的 LLM 厂商对消息格式有不同要求（例如：某些厂商不支持连续的两条 <code>user</code> 消息）。<strong>Message Formatter</strong> 会自动合并、拆分或调整角色类型，以确保请求不会被 API 拒绝。</p><h2 id="调整管道配置" tabindex="-1">调整管道配置 <a class="header-anchor" href="#调整管道配置" aria-label="Permalink to &quot;调整管道配置&quot;">​</a></h2><p>在 <strong>聊天设置 -&gt; 上下文管道</strong> 中：</p><ul><li><strong>启用/禁用</strong>: 某些任务不需要 RAG 或世界书时，关闭对应处理器可些微提升响应速度，但是不推荐这么做，因为这个处理器的开关是全局的，建议在 Agent 中配置对应行为。</li><li><strong>拖拽排序</strong>: 高级用户可以调整处理器的物理顺序。例如，如果你希望正则规则也应用到世界书注入的内容上，可以将 Regex Processor 移动到 Worldbook Processor 之后。</li></ul><hr><h3 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h3><ul><li><a href="./analyzer">上下文分析器</a></li><li><a href="./regex-pipeline">正则管道系统</a></li><li><a href="./token-management">Token 预算管理</a></li></ul></div>',1)])])}const x=e(s,[["render",o]]);export{h as __pageData,x as default};
